import { cx, x } from "@/lib/utils.stylex";

import { styles } from "./message.stylex";

const MessageGroup = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.group);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="message-group"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const Message = ({
  className,
  style,
  align = "start",
  ...props
}: React.ComponentProps<"div"> & { align?: "start" | "end" }) => {
  const p = x(styles.message, align === "end" && styles.messageEnd);
  return (
    <div
      className={cx(p.className, className)}
      data-align={align}
      data-slot="message"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const MessageAvatar = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.avatar);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="message-avatar"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const MessageContent = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.content);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="message-content"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const MessageHeader = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.header);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="message-header"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const MessageFooter = ({
  className,
  style,
  ...props
}: React.ComponentProps<"div">) => {
  const p = x(styles.footer);
  return (
    <div
      className={cx(p.className, className)}
      data-slot="message-footer"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

export {
  MessageGroup,
  Message,
  MessageAvatar,
  MessageContent,
  MessageFooter,
  MessageHeader,
};

import * as stylex from "@stylexjs/stylex";

import { colors } from "@/lib/tokens.stylex";

export const styles = stylex.create({
  avatar: {
    alignItems: "center",
    alignSelf: "flex-end",
    backgroundColor: colors.muted,
    borderRadius: "9999px",
    display: "flex",
    flexShrink: 0,
    justifyContent: "center",
    overflow: "hidden",
    width: "fit-content",
  },
  content: {
    display: "flex",
    flexDirection: "column",
    minWidth: 0,
    overflowWrap: "break-word",
    width: "100%",
  },
  footer: {
    alignItems: "center",
    display: "flex",
    maxWidth: "100%",
    minWidth: 0,
  },
  group: { display: "flex", flexDirection: "column", minWidth: 0 },
  header: {
    alignItems: "center",
    display: "flex",
    maxWidth: "100%",
    minWidth: 0,
  },
  message: {
    display: "flex",
    minWidth: 0,
    position: "relative",
    width: "100%",
  },
  messageEnd: { flexDirection: "row-reverse" },
});
